//UpdateDocumentPath for FPAN Renewal form
const fpaNumber = VV.Form.GetFieldValue("FPAN Number");
const formID = VV.Form.GetFieldValue("Form ID");
let documentUploadPath = `/FPA/TEMP/${formID}`;

const fpaNumberParamsPath = VV.Form.Global.GetFolderPathFromFPANumber(
  fpaNumber,
  false,
  true
);

if (fpaNumberParamsPath) {
  documentUploadPath = `/FPA/${fpaNumberParamsPath}`;
}

return VV.Form.SetFieldValue("Document Upload Path", documentUploadPath);

//VerifyUniqueAndSave for FPAN Renewal
//PARAMS - saveType: 'Draft' or 'Submit'

const webServiceName = 'FPANRenewalVerifyUnique';
const formName = 'FPAN Renewal';
let message; // the message is set below
const oldStatus = VV.Form.GetFieldValue('Status');

VV.Form.ShowLoadingPanel();

function CallServerSide() {
  const formData = [
    {
      name: 'FPAN Number',
      value: VV.Form.GetFieldValue('FPAN Number'),
    },
    {
      name: 'Form ID',
      value: VV.Form.GetFieldValue('Form ID'),
    },
  ];

  // Parse the data as a JSON string
  const data = JSON.stringify(formData);

  const requestObject = $.ajax({
    type: 'POST',
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${webServiceName}`,
    contentType: 'application/json; charset=utf-8',
    data: data,
    success: '',
    error: '',
  });

  return requestObject;
}

$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  if (typeof resp.status != 'undefined') {
    message = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
  } else if (typeof resp.statusCode != 'undefined') {
    message = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server.  This may mean that the servers to run the business logic are not available.`;
  } else if (resp.meta.status == '200') {
    if (resp.data[0] != undefined) {
      if (resp.data[0] == 'Success') {
        if (saveType === 'Submit') {
          VV.Form.SetFieldValue('Status', 'Submitted').then(() => {
            Promise.all([VV.Form.DoAjaxFormSave(), VV.Form.Global.SubmitApplicationUpdate()])
              .then(() =>
                VV.Form.Template.CreateStatusHistory('Submitted', oldStatus)
              )
              .then(() =>
                VV.Form.Template.CreateStatusHistory('Received', 'Submitted')
              );
          });
        } else if (saveType === 'Draft') {
          VV.Form.SetFieldValue('Status', 'Draft').then(VV.Form.Template.SaveDraft());
        }
      } else if (resp.data[0] == 'Error' && resp.data[2].toLowerCase().includes('not unique')) {
        message = `Another FPAN Renewal was already associated with this application. Please review the form information and make any necessary changes.`;
        VV.Form.Global.DisplayModal({
          Title: 'Duplicate Record Found',
          Icon: 'warning',
          HtmlContent: message,
        });
      } else {
        message = `An unhandled response occurred when calling ${webServiceName}. The form will not save at this time.  Please try again or communicate this issue to support.`;
        displayErrorModal('Error', message);
      }
    } else {
      message = 'The status of the response returned as undefined.';
      VV.Form.Global.DisplayMessaging(message, formName);
    }
  } else {
    message = `The following unhandled response occurred while attempting to retrieve data on the server side get data logic. ${resp.data.error} <br>`;
    VV.Form.Global.DisplayMessaging(message, formName);
  }
});

function displayErrorModal(title, messageData) {
  VV.Form.Global.DisplayModal({
    Title: title,
    Icon: 'error',
    HtmlContent: messageData,
  });
}

// CallLibSignatureSendNotifications for FPAN Renewal
const websvcName = 'LibSignatureSendNotifications';

const deferred = $.Deferred();
const CallServerSide = function () {
  VV.Form.ShowLoadingPanel();

  // Create the form data to send to the microservice
  const formData = [
    {
      name: 'Related Record ID',
      value: VV.Form.DhDocID,
    },
  ];

  // Convert form data to JSON and prepare the server-side call
  const data = JSON.stringify(formData);
  const requestObject = $.ajax({
    type: 'POST',
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });

  return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  let messageData = '';
  let resolvePromise = false;
  let callData = {};
  if (typeof resp.status != 'undefined') {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != 'undefined') {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
    displayErrorModal(messageData);
  } else if (resp.meta.status == '200') {
    if (resp.data[0] !== 'undefined') {
      if (resp.data[0] === 'Success') {
        resolvePromise = true;
        callData = resp.data[2]
      } else if (resp.data[0] === 'Error') {
        messageData = `An error was encountered. ${resp.data[1]}`;
        displayErrorModal(messageData);
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
        displayErrorModal(messageData);
      }
    } else {
      messageData = 'The status of the response returned as undefined.';
      displayErrorModal(messageData);
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
    displayErrorModal(messageData);
  }
  // resolve/reject promise
  if (resolvePromise) {
    deferred.resolve(callData);
  } else {
    deferred.reject(messageData);
  }
});

function displayErrorModal(messageData) {
  VV.Form.Global.DisplayModal({
    Title: 'Error',
    Icon: 'error',
    HtmlContent: messageData,
  });
}

return deferred.promise();

// LibGetApplicationReviewPageRelatedData for Application Review Page

const webServiceName = 'LibGetApplicationReviewPageRelatedData';
const formName = 'Application Review Page';
let message; // the message is set below

VV.Form.ShowLoadingPanel();


let deferred = $.Deferred();

function CallServerSide() {
    let formData = []

    // Uncomment the following to add more data to the formData object.
    let moreData = {
       name: 'FPAN Number',
       value: VV.Form.GetFieldValue('FPAN Number')
    };
    formData.push(moreData);

    moreData = {
        name: 'Type',
        value: 'RENEWAL'
    }
    formData.push(moreData);

    // Parse the data as a JSON string
    const data = JSON.stringify(formData);

    const requestObject = $.ajax({
        type: 'POST',
        url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${webServiceName}`,
        contentType: 'application/json; charset=utf-8',
        data: data,
        success: '',
        error: '',
    });

    return requestObject;
}

$.when(CallServerSide())
    .always(function (resp) {

        let resolvePromise = false;
        let data = {};
        VV.Form.HideLoadingPanel();

        if (typeof resp.status != 'undefined') {
            message = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
        } else if (typeof resp.statusCode != 'undefined') {
            message = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server.  This may mean that the servers to run the business logic are not available.`;
        } else if (resp.meta.status == '200') {
            if (resp.data[0] != undefined) {
                if (resp.data[0] == 'Success') {
                    message = `${formName} has been saved successfully.`;

                    // HANDLE SUCCESS RESPONSE HERE
                    resolvePromise = true;

                    data = resp.data[2]

                } else if (resp.data[0] == 'Error') {
                    message = `An error was encountered. ${resp.data[1]}`;
                    VV.Form.Global.DisplayModal({
                        Title: 'Error',
                        Icon: 'error',
                        HtmlContent: message
                    })
                } else {
                    message = `An unhandled response occurred when calling ${webServiceName}. The form will not save at this time.  Please try again or communicate this issue to support.`;
                    VV.Form.Global.DisplayModal({
                        Title: 'Error',
                        Icon: 'error',
                        HtmlContent: message
                    })
                }
            } else {
                message = 'The status of the response returned as undefined.';
                VV.Form.Global.DisplayModal({
                    Title: 'Error',
                    Icon: 'error',
                    HtmlContent: message
                })
            }
        } else {
            message = `The following unhandled response occurred while attempting to retrieve data on the server side get data logic. ${resp.data.error} <br>`;
            VV.Form.Global.DisplayModal({
                Title: 'Error',
                Icon: 'error',
                HtmlContent: message
            })
        }

        // resolve/reject promise
        if (resolvePromise) {
            Promise.all([
                data.fpanExpirationDate && VV.Form.SetFieldValue('Expiration Date Of Approved FPAN', data.fpanExpirationDate)
            ]).then(() => {
                deferred.resolve();
            });
        } else {
            deferred.reject(message);
        }
    })

return deferred.promise();

// Resubmit for FPAN Renewal
const isProponent = VV.Form.GetFieldValue('isProponent') === 'True';

const isValid = !isProponent || (isProponent && VV.Form.Template.FormValidation());
const oldStatus = VV.Form.GetFieldValue('Status');

if (isValid) {
  VV.Form.Global.DisplayModal({
    Title: 'Confirm',
    Icon: 'question',
    HtmlContent: 'Do you want to move forward with the process?',
    okFunction: () => {
      VV.Form.SetFieldValue('Status', 'Revision Received')
        .then(() => VV.Form.DoAjaxFormSave())
        .then(() => VV.Form.Template.CallLibUpdateApplicationReviewPage())
        .then(() => VV.Form.Template.CreateStatusHistory('Revision Received', oldStatus))
        .then(() => {
          VV.Form.Global.DisplayModal({
            Title: 'Form Saved',
            Icon: 'success',
            HtmlContent: 'Form has been resubmitted successfully.',
          });
        });
    },
  });
} else {
  VV.Form.Global.ValidationModal();
}

// LibUpdateApplicationReviewPage for FPAN Renewal

const webServiceName = 'LibUpdateApplicationReviewPage';
const formName = 'FPAN Renewal';
let message; // the message is set below

VV.Form.ShowLoadingPanel();

function CallServerSide() {
  // Get application type from FPAN Number
  let applicationType;

  return VV.Form.CustomQuery(
    'zLookup Application Type By FPAN',
    VV.Form.GetFieldValue('FPAN Number')
  ).then((res) => {
    applicationType = res[0]['application Type'];

    const updatedAt = new Date().toLocaleString('en-US', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: true,
    });

    const formData = [
      { name: 'Form ID', value: VV.Form.GetFieldValue('Form ID') },
      { name: 'Region', value: VV.Form.GetFieldValue('Region') },
      { name: 'FPAN Number', value: VV.Form.GetFieldValue('FPAN Number') },
      { name: 'Application Type', value: applicationType },
      { name: 'Update Client Side', value: 'yes' },
      { name: 'Renewal Status Updated At', value: updatedAt}
    ];

    // Parse the data as a JSON string
    const data = JSON.stringify(formData);

    // Return the AJAX request's promise
    return $.ajax({
      type: 'POST',
      url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${webServiceName}`,
      contentType: 'application/json; charset=utf-8',
      data: data,
    });
  });
}

$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  if (typeof resp.status != 'undefined') {
    message = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
  } else if (typeof resp.statusCode != 'undefined') {
    message = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server.  This may mean that the servers to run the business logic are not available.`;
  } else if (resp.meta.status == '200') {
    if (resp.data[0] != undefined) {
      if (resp.data[0] == 'Success') {
        // HANDLE SUCCESS RESPONSE HERE
        // Alway use .then for waiting for the form to save before running another function
        Promise.all([
          VV.Form.SetFieldValue('Status', 'Received'),
          VV.Form.SetFieldValue('Date of Receipt', resp.data[2]['Date of Receipt']),
        ])
          .then(VV.Form.Template.SetButtonVisibility)
          .then(() => {
            VV.Form.ShowLoadingPanel();
            VV.Form.DoAjaxFormSave().then(() => {
              const syncARPCallback = () => {
                VV.Form.HideLoadingPanel();
                VV.Form.Global.DisplayModal({
                  Title: 'Form Submitted',
                  Icon: 'success',
                  HtmlContent: `${formName} has been saved successfully.`,
                });
              };

              VV.Form.Global.SyncARP(syncARPCallback);
            });
          });
      } else if (resp.data[0] == 'Error') {
        message = `An error was encountered. ${resp.data[1]}`;
        showErrorModal(message);
      } else {
        message = `An unhandled response occurred when calling ${webServiceName}. The form will not save at this time.  Please try again or communicate this issue to support.`;
        showErrorModal(message);
      }
    } else {
      message = 'The status of the response returned as undefined.';
      showErrorModal(message);
    }
  } else {
    message = `The following unhandled response occurred while attempting to retrieve data on the server side get data logic. ${resp.data.error} <br>`;
    showErrorModal(message);
  }
});

function showErrorModal(message) {
  VV.Form.Global.DisplayModal({
    Title: 'Error',
    Icon: 'error',
    HtmlContent: message,
  });
}

// SetIndividual for FPAN Renewal
return VV.Form.Global.CallLibGetIndividual(VV.Form.FormUserID)
  .then((individualObj) =>
    Promise.allSettled([
      VV.Form.SetFieldValue("Individual ID", individualObj["Form ID"]),
      VV.Form.SetFieldValue("UserID", individualObj["UserID"]),
    ])
  )
  .catch((error) => {
    console.error(error);
    VV.Form.Global.DisplayModal({
      Title: "Related individual not found",
      Icon: "warning",
      HtmlContent:
        "The related Individual could not be located. If you require assistance, please contact our support team.",
      allowOutsideClick: false,
      ConfirmText: "Ok",
      okFunction: () => window.close(),
      showCancelButton: false,
      showDenyButton: true,
    });
  });

// Timber OwnerSearch for Contact Records on FPAN form
const websvcName = "LibContactInformationSearch";
let modalContent;

// Define the maximum number of results allowed before prompting the user to refine their search
const recordThreshold = 50;

let CallServerSide = function () {
    VV.Form.ShowLoadingPanel();

    // Create the form data to send to the microservice
    const formData = [
        { name: "First Name", value: VV.Form.GetFieldValue("Timber Owner Search First Name") },
        { name: "Last Name", value: VV.Form.GetFieldValue("Timber Owner Search Last Name") },
        { name: "Country", value: VV.Form.GetFieldValue("Timber Owner Search Country") },
        { name: "Zip Code", value: VV.Form.GetFieldValue("Timber Owner Search Postal Zip Code") },
        { name: "Address Line 1", value: VV.Form.GetFieldValue("Timber Owner Search Address Line 1") },
        { name: "Address Line 2", value: VV.Form.GetFieldValue("Timber Owner Search Address Line 2") },
        { name: "Address Line 3", value: VV.Form.GetFieldValue("Timber Owner Search Address Line 3") },
        { name: "City", value: VV.Form.GetFieldValue("Timber Owner Search City") },
        { name: "State", value: VV.Form.GetFieldValue("Timber Owner Search Province State") },
        { name: "County", value: VV.Form.GetFieldValue("Timber Owner Search County") },
        { name: "Phone", value: VV.Form.GetFieldValue("Timber Owner Search Phone") },
        { name: "Email", value: VV.Form.GetFieldValue("Timber Owner Search Email") },
    ];

    // Convert form data to JSON and prepare the server-side call
    let data = JSON.stringify(formData);
    let requestObject = $.ajax({
        type: "POST",
        url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
        contentType: `application/json; charset=utf-8`,
        data: data,
    });

    return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
    VV.Form.HideLoadingPanel();
    let messageData = "";

    if (typeof resp.status != "undefined") {
        messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
        displayErrorModal(messageData);
    } else if (typeof resp.statusCode != "undefined") {
        messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
        displayErrorModal(messageData);
    } else if (resp.meta.status == "200") {
        if (resp.data[0] !== "undefined") {
            if (resp.data[0] === "Success") {
                const searchResults = resp.data[2].results;

                // Check if the number of records exceeds the threshold
                if (searchResults.length >= recordThreshold) {
                    modalContent = `Too many results were returned. Please refine your search criteria to narrow down the results.`;
                    VV.Form.Global.DisplayModal({
                        Icon: "warning",
                        Title: "Refine Search",
                        HtmlContent: modalContent,
                        showCancelButton: false,
                        ConfirmText: "OK",
                    });
                } else if (searchResults.length > 0) {
                    // Format the search results to be displayed in rows, using predefined keys
                    const recordsArray = searchResults.map((record) => ({
                        "first Name": record["first Name"] || "N/A",
                        "last Name": record["last Name"] || "N/A",
                        "contact Information ID": record["contact Information ID"] || "N/A",
                        "address Line 1": record["address Line 1"] || "N/A",
                        city: record["city"] || "N/A",
                        state: record["state"] || "N/A",
                        "zip Code": record["zip Code"] || "N/A",
                        phone: record["phone"] || "N/A",
                    }));

                    // Display the modal with results, passing callback functions
                    VV.Form.Template.AddTimberOwnerContactModal(
                        recordsArray,
                        addTimberOwnerCallback,
                        clearFieldsCallback
                    );
                } else {
                    messageData = `No contact records were found for the given search parameters. If you would like to add a new contact, please click the 'Add New Contact' button, or click 'Cancel' to refine your search.`;

                    VV.Form.Global.DisplayModal({
                        Icon: "warning",
                        Title: "No Results Found",
                        HtmlContent: messageData,
                        Width: 600,
                        ConfirmText: "Add New Contact",
                        dismissFunction: clearFieldsCallback,
                        showCancelButton: true,
                        okFunction: function () {
                            console.log("Add New Contact button clicked");
                            // Create a new object with the Timber Owner details
                            const timberOwner = {
                                firstName: VV.Form.GetFieldValue("Timber Owner Search First Name"),
                                lastName: VV.Form.GetFieldValue("Timber Owner Search Last Name"),
                                country: VV.Form.GetFieldValue("Timber Owner Search Country"),
                                postalZipCode: VV.Form.GetFieldValue("Timber Owner Search Postal Zip Code"),
                                addressLine1: VV.Form.GetFieldValue("Timber Owner Search Address Line 1"),
                                addressLine2: VV.Form.GetFieldValue("Timber Owner Search Address Line 2"),
                                addressLine3: VV.Form.GetFieldValue("Timber Owner Search Address Line 3"),
                                city: VV.Form.GetFieldValue("Timber Owner Search City"),
                                provinceState: VV.Form.GetFieldValue("Timber Owner Search Province State"),
                                county: VV.Form.GetFieldValue("Timber Owner Search County"),
                                phone: VV.Form.GetFieldValue("Timber Owner Search Phone"),
                                email: VV.Form.GetFieldValue("Timber Owner Search Email"),
                            };
                            // Pass the object to the AddTimber OwnerContact function
                            VV.Form.Template.AddTimberOwnerContact(timberOwner);
                        },
                    });
                }
            } else if (resp.data[0] === "Error") {
                messageData = `An error was encountered. ${resp.data[1]}`;
                displayErrorModal(messageData);
            } else {
                messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
                displayErrorModal(messageData);
            }
        } else {
            messageData = "The status of the response returned as undefined.";
            displayErrorModal(messageData);
        }
    } else {
        messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
        displayErrorModal(messageData);
    }
});

// Callback function to add the selected contact record and other params
function addTimberOwnerCallback(formID, timberOwnerSameAs, operatorSameAs, businessID) {
    console.log("Callback success: formID: ", formID);
    console.log("Callback success: businessID: ", businessID);
    console.log("Callback success: timberOwnerSameAs: ", timberOwnerSameAs);
    console.log("Callback success: operatorSameAs: ", operatorSameAs);

    // Construct the roles array based on the boolean parameters
    let roles = ["Timber Owner"];
    // Call the AddTimber Owner function with the required parameters
    VV.Form.Template.AddTimberOwner(formID, roles, businessID);
    clearFieldsCallback();
    // Future script call
}
// Callback function to clear the field values
