    VV.Form.SetFieldValue("Timber Owner Search Address Line 3", "");
    VV.Form.SetFieldValue("Timber Owner Search City", "");
    VV.Form.SetFieldValue("Timber Owner Search Province State", "Select Item");
    VV.Form.SetFieldValue("Timber Owner Search County", "Select Item");
    VV.Form.SetFieldValue("Timber Owner Search Phone", "");
    VV.Form.SetFieldValue("Timber Owner Search Email", "");
    console.log("Search fields cleared.");
}

// Display error modal
function displayErrorModal(messageData) {
    VV.Form.Global.DisplayModal({
        Title: "Error",
        Icon: "error",
        HtmlContent: messageData,
    });
}

