// CallLibRenewalGenerateFee for FPAN Renewal
const websvcName = "LibRenewalGenerateFeeSummary";

const deferred = $.Deferred();
const CallServerSide = function () {
  VV.Form.ShowLoadingPanel();

  // Create the form data to send to the microservice
  const formData = [
    {
      name: "Renewal Form ID",
      value: VV.Form.DhDocID,
    },
    {
      name: "User ID",
      value: VV.Form.FormUserID,
    },
    {
      name: "No Payment Required",
