/* DeterminePayNowButtonVisibility for FPAN Renewal - Determines if the "Pay Now" button should be displayed on the Fees tab and 
  sets a checkbox that controls the visibility as appropriate.
   Parameters: none
   Return Value: (Promise) Resolves when all calculations and field updates have resolved
*/
const payableStatuses = ['Required Signatures Received', 'Pending Revisions'];
const inPayableStatus = payableStatuses.includes(VV.Form.GetFieldValue('Status'));
const isNotOfficeStaff = VV.Form.FormUserGroups.includes('Office Staff') === false;

const mainPromise = Promise.resolve().then(() => {
  // hide by default
  return VV.Form.SetFieldValue('Show Pay Now Button', 'False');
});

if (inPayableStatus && isNotOfficeStaff) {
  mainPromise.then(() => {
    return VV.Form.Global.GetPendingRelatedFees();
  }).then((relatedFeeData) => {
    const hasPendingRelatedFees = relatedFeeData.length > 0;
    if (hasPendingRelatedFees) {
      return VV.Form.SetFieldValue('Show Pay Now Button', 'True');
    }
  });
}

return mainPromise;

