        // Check if the record was updated
        const recordUpdated = !!resp.data?.[2]?.recordUpdated;
        if (recordUpdated) {
          // Extract updated fields from the response
          const updatedFields = resp.data?.[2]?.updatedFields || {};
          const updatedFieldsList = Object.entries(updatedFields)
