}

if (section === false) return Promise.reject('Clear fields for Search section failed. You need to pass the section name as a requirement.');

// Clear Search Fields

return Promise.all(

    Object.keys(fieldsToclear).map(type =>
        Promise.all(
            Object.entries(fieldsToclear[type]).map( ([key, value]) =>
                VV.Form.SetFieldValue(`${section} ${key}`, value)
            )
        )
    )  
);

// ValidateAndProceed for FPAN Renewal
const isProponent = VV.Form.GetFieldValue('isProponent') === 'True';
if (!isProponent) return;

const isValid = VV.Form.Template.FormValidation();
if (isValid) {
  VV.Form.Global.DisplayModal({
    Title: 'Confirm',
    Icon: 'question',
    HtmlContent: 'Do you want to move forward with the process?',
    okFunction: () => {
      VV.Form.Template.VerifyUnique()
      .then((res) => {
        if(res.success){
          if(res.unique){
            return generateFeeAndShowSendForSignature();
          } else {            
            return VV.Form.Global.DisplayModal({
                Title: 'Duplicate Record Found',
                Icon: 'warning',
                HtmlContent: res.message,
            });
          }
        }else{
          throw new Error(res.message);
        }        
      })
      .then(() => VV.Form.RefreshDataGridControl("DG Fees"))
      .then(() => VV.Form.SetFieldValue('Show Send for Signature', 'True', true))
      .then(() => VV.Form.Template.SetButtonVisibility())
      .then(() => VV.Form.DoAjaxFormSave())
      .catch((message) => {
        VV.Form.Global.DisplayModal({
          Title: 'An error happened when validating',
          Icon: 'error',
          HtmlContent: message,
        });
      });
    },
  });
} else {
  VV.Form.Global.ValidationModal();
}

function generateFeeAndShowSendForSignature() {
  return VV.Form.Template.CallLibRenewalGenerateFee()
    .then((feeAmount) => {
        //VV.Form.SetFieldValue("No Fees Required", feeAmount === 0 ? "True" : "False");
        VV.Form.SetFieldValue('Fees Assesed', 'True');

        //Check again all fees, in case the user is Re-Validating and a higher fee was already associated
        return VV.Form.Global.GetPendingRelatedFees();
    })
    .then((result) => {
        VV.Form.SetFieldValue("No Fees Required", (result.length > 0) ? "False" : "True");
        let message = `$0.00 in the total fees assessed.`
        let flagUpdates = [];
        if(result.length > 0){
          message = `Payment of $${result[0]['total Amount Due']} can be made in the Shopping Cart once all required signatures have been obtained.`

          // If fees required, set autosubmission flags
          const dateOfReceipt = VV.Form.GetFieldValue('Date of Receipt');
          if(dateOfReceipt === '' || dateOfReceipt === null || dateOfReceipt === 'Invalid Date'){
            flagUpdates = [
              VV.Form.SetFieldValue("AutoSubmissionNeeded", "True"),
              VV.Form.SetFieldValue("AutoResubmitNeeded", "False"),
            ];
          } else {
            flagUpdates = [
              VV.Form.SetFieldValue("AutoSubmissionNeeded", "False"),
              VV.Form.SetFieldValue("AutoResubmitNeeded", "True"),
            ];
          }            
        } else {
          flagUpdates = [
            VV.Form.SetFieldValue("AutoSubmissionNeeded", "False"),
            VV.Form.SetFieldValue("AutoResubmitNeeded", "False"),
          ];
        }        

        return Promise.all(flagUpdates).then(function () {
          return VV.Form.Global.DisplayModal({
            Icon: "success",
            Title: "Success",
            HtmlContent: message,
          });
        });
    })
    .catch((error) => {
      VV.Form.Global.DisplayModal({
        Title: 'Error',
        Icon: 'error',
        HtmlContent: error,
      });
    });
}

//AddBusiness for FPAN Renewal
//Params - formID, businessName, roles (array of roles)

const websvcName = "LibCreateContactInformationRelation";
let modalContent;

let CallServerSide = function () {
  VV.Form.ShowLoadingPanel();
  // Create the form data to send to the microservice
  const formData = [
    {
      name: "Relation Type",
      value: "Business",
    },
    {
      name: "Related Record ID",
      value: VV.Form.DhDocID,
    },
    {
      name: "Contact Information ID",
      value: formID,
    }
  ];

  // Ensure 'roles' is an array before iterating
  if (Array.isArray(roles)) {
    // Iterate through the roles array and add them to the form data
    roles.forEach(function (roleName) {
      formData.push({
        name: roleName,
        value: "True",
      });
    });
  }

  // Convert form data to JSON and prepare the server-side call
  let data = JSON.stringify(formData);
  let requestObject = $.ajax({
    type: "POST",
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });
  return requestObject;
};
$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  let messageData = "";
  if (typeof resp.status != "undefined") {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != "undefined") {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
    displayErrorModal(messageData);
  } else if (resp.meta.status == "200") {
    if (resp.data[0] !== "undefined") {
      if (resp.data[0] === "Success") {

        VV.Form.Global.DisplayModal({
          Title: "Business Associated",
          Icon: "success",
          HtmlContent: `<div style="align-items: center; gap: 1rem; width: 100%; font-size: 1.1em;">
                <p>You've successfully associated the business:</p>
                <p style="font-weight: bold;">[${businessName}]</p>
                <p>as a ${roles[0]} to this application.</p>
                </div>`,
          showCancelButton: false,
          allowOutsideClick: false,
          okFunction: function () {
            clearFieldsCallback()
              .then(() => {
                VV.Form.Global.RefreshFormElements();
              })
              .then(() => {
                VV.Form.DoAjaxFormSave();
              })
              .catch((err) => {
                console.error("Error when adding business:", err);
              });
          },
        });
        /*VV.Form.SetFieldValue("Multiple Landowners", true)
          .then(() => {
            VV.Form.RefreshDataGridControl("DG Businesses");
          })
          .then(VV.Form.DoAjaxFormSave());*/

      } else if (resp.data[0] === "Error") {
        messageData = `An error was encountered. ${resp.data[1]}`;
        console.log(messageData);
        displayErrorModal();
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
        console.log(messageData);
        displayErrorModal();
      }
    } else {
      messageData = "The status of the response returned as undefined.";
      console.log(messageData);
      displayErrorModal();
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
    console.log(messageData);
    displayErrorModal();
  }
});
