currentField = 'Small Forest Landowner';
currentValue = VV.Form.GetFieldValue(currentField);

if (isProponent && (ControlName == currentField || RunAll)) {
  if (VV.Form.Global.CentralValidation(currentValue, 'DDSelect') == false) {
    VV.Form.SetValidationErrorMessageOnField(currentField, 'A value needs to be selected.');
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField(currentField);
  }
}

// Proposed Harvest - mandatory
currentField = 'Proposed Harvest';
currentValue = VV.Form.GetFieldValue(currentField);

if (isProponent && (ControlName == currentField || RunAll)) {
  if (
    VV.Form.GetFieldValue('Small Forest Landowner') === 'Yes' &&
    VV.Form.Global.CentralValidation(currentValue, 'DDSelect') == false
  ) {
    VV.Form.SetValidationErrorMessageOnField(currentField, 'A value needs to be selected.');
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField(currentField);
  }
}

return ErrorReporting;

//SetButtonVisibility for FPAN Renewal
const doesNotRequirePayment = 
  VV.Form.GetFieldValue('Does Not Require Payment') === 'True' || VV.Form.GetFieldValue("No Fees Required") === "True";
const formStatus = VV.Form.GetFieldValue('Status');
const roles = VV.Form.Global.GetCurrentRoles();

const isProponent = roles.includes('proponent');
const isOfficeStaff = roles.includes('office staff');

let setSubmitButtonVisible = false;
let setResubmitButtonVisible = false;

if (isProponent) {
  if (['Needs Submission'].includes(formStatus)) {
    setSubmitButtonVisible = true;
  }
  if (['Required Signatures Received'].includes(formStatus) && doesNotRequirePayment) {
    setSubmitButtonVisible = true;
  }
  if (['Pending Revisions'].includes(formStatus) && doesNotRequirePayment) {
    setResubmitButtonVisible = true;
  }
  if (['Needs Resubmission'].includes(formStatus)) {
    setResubmitButtonVisible = true;
  }

  // Hide buttons if autosubmission is needed
  if(VV.Form.GetFieldValue('AutoSubmissionNeeded') === 'True'){
    setSubmitButtonVisible = false;
  }
  if(VV.Form.GetFieldValue('AutoResubmitNeeded') === 'True'){
    setResubmitButtonVisible = false;
  }
}

if (isOfficeStaff) {
  if (formStatus === 'Draft') {
    setSubmitButtonVisible = true;
  }
  if (formStatus === 'Pending Revisions') {
    setResubmitButtonVisible = true;
  }
}

return Promise.all([
  VV.Form.SetFieldValue('Show Submit Button', setSubmitButtonVisible ? 'True' : 'False'),
  VV.Form.SetFieldValue('Show Resubmit Button', setResubmitButtonVisible ? 'True' : 'False'),
]);

