// Function to display the "Same As" modal
function showSameAsModal(record) {
  // Retrieve saved selections from session storage
  const savedTimberOwnerSameAs =
    sessionStorage.getItem("timberOwnerSameAs") || "";
  const savedOperatorSameAs = sessionStorage.getItem("operatorSameAs") || "";

  const sameAsHtml = `
  <p style="text-align: left; line-height: 1.6;">Please answer the following questions before adding the contact:</p>
  <div style="display: flex; flex-direction: column; gap: 1rem; padding: 1rem 0;">
    <div style="display: flex; align-items: center; gap: 1rem; width: 100%;">
      <label for="timberOwnerSameAs" style="flex: 1 0 50%; text-align: left; white-space: nowrap;">
        Is the Timber Owner the same as the ${term}?
      </label>
      <select id="timberOwnerSameAs" style="flex: 1 0 25%; padding: 0.3rem;">${dropdownOptions}</select>
    </div>
    <div style="display: flex; align-items: center; gap: 1rem; width: 100%;">
      <label for="operatorSameAs" style="flex: 1 0 50%; text-align: left; white-space: nowrap;">
        Is the Operator the same as the ${term}?
      </label>
      <select id="operatorSameAs" style="flex: 1 0 25%; padding: 0.3rem;">${dropdownOptions}</select>
    </div>
  </div>
`;

  Swal.fire({
    icon: "question",
    title: `Same as ${term}?`,
    html: sameAsHtml,
    showCancelButton: true,
    showConfirmButton: true,
    showDenyButton: true,
    allowOutsideClick: false,
    confirmButtonText: "Back",
    denyButtonText: "Next",
    cancelButtonText: "Cancel",
    width: "50rem", // Modal width
    customClass: {
      confirmButton: "blue-button back-button",
      denyButton: "blue-button next-button",
      cancelButton: "blue-button cancel-button",
    },
    preDeny: () => {
      const timberOwnerValue =
        document.getElementById("timberOwnerSameAs").value;
      const operatorValue = document.getElementById("operatorSameAs").value;

      if (!timberOwnerValue || !operatorValue) {
        Swal.showValidationMessage(
          `The 'Same As ${term}' questions must be answered.`
        );
        return false;
      }

      // Save selections to session storage
      sessionStorage.setItem("timberOwnerSameAs", timberOwnerValue);
      sessionStorage.setItem("operatorSameAs", operatorValue);

      return {
        timberOwnerSameAs: timberOwnerValue,
        operatorSameAs: operatorValue,
      };
    },
    didRender: () => {
      // Rearrange buttons
      const actions = Swal.getActions(); // Get the actions container
      const confirmButton = Swal.getConfirmButton(); // Back button
      const denyButton = Swal.getDenyButton(); // Next button
      const cancelButton = Swal.getCancelButton(); // Cancel button

      // Set custom order using flexbox order property
      confirmButton.style.order = 1; // Back button
      denyButton.style.order = 2; // Next button
      cancelButton.style.order = 3; // Cancel button

      // Ensure the actions container uses flexbox
      actions.style.display = "flex";

      // Directly modify the deny button style after rendering
      $(".swal2-deny").css({
        "background-color": $(".swal2-confirm").css("background-color"),
        color: $(".swal2-confirm").css("color"),
      });

      // Set the dropdowns to saved values if available
      document.getElementById("timberOwnerSameAs").value =
        savedTimberOwnerSameAs;
      document.getElementById("operatorSameAs").value = savedOperatorSameAs;
    },
  }).then((result) => {
    if (result.isConfirmed) {
      showSelectContactModal(); // Go back to the "Select Contact" modal
    } else if (result.isDenied) {
      const { timberOwnerSameAs, operatorSameAs } = result.value;
      // Proceed to Add Contact modal, pass the record and same as values
      showAddContactModal(record, timberOwnerSameAs, operatorSameAs); // Call the "Add Contact" modal
    } else if (result.isDismissed) {
      // Clear selections if modal is dismissed via Cancel button
      sessionStorage.removeItem("timberOwnerSameAs");
      sessionStorage.removeItem("operatorSameAs");

      // Call clearFieldsCallback when modal is closed or canceled
      clearFieldsCallback();
    }
  });
}

// Function to display the "Add Contact" modal
function showAddContactModal(record, timberOwnerSameAs, operatorSameAs) {
  const addContactHtml = `
    <div style="text-align: left; line-height: 1.6;">
      <p>Are you sure you want to associate the selected contact?</p>
      <p><strong>Name:</strong> ${record["first Name"]} ${record["last Name"]}</p>
      <p><strong>${term} same as Timber Owner:</strong> ${timberOwnerSameAs}</p>
      <p><strong>${term} same as Operator:</strong> ${operatorSameAs}</p>
    </div>
  `;

  Swal.fire({
    icon: "question",
    title: "Add Contact",
    html: addContactHtml,
    showCancelButton: true,
    showConfirmButton: true,
    showDenyButton: true,
    allowOutsideClick: false,
    confirmButtonText: "Back",
    denyButtonText: "Add Contact",
    cancelButtonText: "Cancel",
    width: "40rem", // Modal width for Add Contact
    didRender: () => {
      // Rearrange buttons
      const actions = Swal.getActions(); // Get the actions container
      const confirmButton = Swal.getConfirmButton(); // Back button
      const denyButton = Swal.getDenyButton(); // Add Contact button
      const cancelButton = Swal.getCancelButton(); // Cancel button

      // Set custom order using flexbox order property
      confirmButton.style.order = 1; // Back button
      denyButton.style.order = 2; // Add Contact button
      cancelButton.style.order = 3; // Cancel button

      // Directly modify the deny button style after rendering
      $(".swal2-deny").css({
        "background-color": $(".swal2-confirm").css("background-color"),
        color: $(".swal2-confirm").css("color"),
      });

      // Ensure the actions container uses flexbox
      actions.style.display = "flex";
    },
  }).then((result) => {
    if (result.isConfirmed) {
      showSameAsModal(record); // Go back to the "Same As" modal
    } else if (result.isDenied) {
      // Clear selections when contact is added
      sessionStorage.removeItem("timberOwnerSameAs");
      sessionStorage.removeItem("operatorSameAs");

      // Console log the Contact Information ID and "Same As..." answers
      console.log("Contact Information ID:", record["contact Information ID"]);
      console.log("Business ID:", record["business ID"]);
      console.log("Timber Owner Same As:", timberOwnerSameAs);
      console.log("Operator Same As:", operatorSameAs);

      // Pass the contact ID and answers to the callback function
      VV.Form.DoAjaxFormSave().then(() => {
        addContactInformationCallback(
          record["contact Information ID"],
          timberOwnerSameAs,
          operatorSameAs,
          record["business ID"]
        );
      });
    } else if (result.isDismissed) {
      // Clear selections if modal is dismissed via Cancel button
      sessionStorage.removeItem("timberOwnerSameAs");
      sessionStorage.removeItem("operatorSameAs");

      // Call clearFieldsCallback when modal is closed or canceled
      clearFieldsCallback();
    }
  });
}

