function displayErrorModal(messageData) {
  const unableText = `Unable to add ${label}`;
  let icon = "error";
  if (messageData.includes("Duplicate")) {
    icon = "warning";
    messageData = `Duplicate Found: The selected ${label} is already associated with this application.`;
  }
  VV.Form.Global.DisplayModal({
    Title: unableText,
    Icon: icon,
    HtmlContent: messageData,
  });
}

// GetFPANData for FPAN Renewal

const webServiceName = 'LibFPANGetRelatedData';
const formName = 'FPAN Renewal';
let message; // the message is set below

VV.Form.ShowLoadingPanel();

function CallServerSide() {

    let formData  = [
        { name: 'relatedRecordID', value: VV.Form.GetFieldValue("FPAN Number") },
        { name: 'Form ID', value: VV.Form.DhDocID}
    ]

    // Parse the data as a JSON string
    const data = JSON.stringify(formData);

    const requestObject = $.ajax({
        type: 'POST',
        url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${webServiceName}`,
        contentType: 'application/json; charset=utf-8',
        data: data,
        success: '',
        error: '',
    });

    return requestObject;
}

return $.when(CallServerSide())
    .always(function (resp) {
        if (typeof resp.status != 'undefined') {
            message = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
        } else if (typeof resp.statusCode != 'undefined') {
            message = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server.  This may mean that the servers to run the business logic are not available.`;
        } else if (resp.meta.status == '200') {
            if (resp.data[0] != undefined) {
                if (resp.data[0] == 'Success') {

                    VV.Form.SetFieldValue("Region", resp.data[2]['Region']); 
                    VV.Form.SetFieldValue("Project Name", resp.data[2]['Project Name']); 

                    VV.Form.RefreshDataGridControl("DG Landowner Businesses");
                    VV.Form.RefreshDataGridControl("DG Landowners");
                    VV.Form.RefreshDataGridControl("DG Timber Owner Businesses");
                    VV.Form.RefreshDataGridControl("DG Timber Owners");
                    VV.Form.RefreshDataGridControl("DG Operator Businesses");
                    VV.Form.RefreshDataGridControl("DG Operators");

                    VV.Form.HideLoadingPanel();

                } else if (resp.data[0] == 'Error') {
                    message = `The related application form could not be located. However, you may still complete the form manually. If you require assistance, please contact our support team.`;
                    VV.Form.Global.DisplayModal({
                            Icon: 'info',
                            Title: 'Application Form Not Found',
                            HtmlContent: message,
                      })
                    VV.Form.SetFieldValue('Related Record ID', VV.Form.DhDocID)
                    VV.Form.HideLoadingPanel();
                } else {
                    message = `An unhandled response occurred when calling ${webServiceName}. The form will not save at this time.  Please try again or communicate this issue to support.`;
                    VV.Form.Global.DisplayModal({
                            Icon: 'error',
                            Title: 'Error',
                            HtmlContent: message,
                      })
                    VV.Form.HideLoadingPanel();
                }
            } else {
                message = 'The status of the response returned as undefined.';
                VV.Form.Global.DisplayModal({
                            Icon: 'error',
                            Title: 'Error',
                            HtmlContent: message,
                      })
                VV.Form.HideLoadingPanel();
            }
        } else {
            message = `The following unhandled response occurred while attempting to retrieve data on the server side get data logic. ${resp.data.error} <br>`;
            VV.Form.Global.DisplayModal({
                            Icon: 'error',
                            Title: 'Error',
                            HtmlContent: message,
                      })
            VV.Form.HideLoadingPanel();
        }
    })

