      addNewBusinessRecord();
    } else if(result.isDismissed) {
      clearFieldsCallback();
    }
  });

  // Style adjustments for the modal content
  $(".records-container").css({
    "max-height": "320px",
    "overflow-y": "auto",
    "overflow-x": "auto",
  });

  $(".record-table").css({
