const isBusinessSigner = VV.Form.GetFieldValue(`${role} Business Or Individual`) === "Business";

// Generate HTML table rows for each business record
const recordHtmlArray = records.map(record => `
  <tr class="record-row">
    <td>${record['first Name'] || 'N/A'}</td>
    <td>${record['last Name'] || 'N/A'}</td>
