    <td>${record['phone'] || 'N/A'}</td>
    <td>
      <button class="k-button add-btn" 
      data-formid="${record['contact Information ID']}" 
      data-firstName="${record['first Name']}"
      data-lastName="${record['last Name']}">
        Select Contact
      </button>
    </td>
