`).join("");

// Complete HTML structure for the modal, including table headers and rows
const recordHtml = `
  <style>
    .selected-row {
      background-color: #cce5ff !important;
      font-weight: bold;
    }
  </style>
  <p>Please select one of the contact records below and click 'Select Contact' to associate a contact as a ${mainRole} with this application. Note: To make changes to your contact record (e.g., mailing address) please contact your local region office. This can be done before or after you have submitted your application</p>
  <div class="records-container">
    <table class="record-table">
      <thead>
        <tr>
          <th>First Name</th>
          <th>Last Name</th>
          <th>Address</th>
          <th>City</th>
          <th>State/Province</th>
          <th>Postal/Zip Code</th>
          <th>Phone</th>
          <th></th>
        </tr>
      </thead>
      <tbody>
        ${recordHtmlArray}
      </tbody>
    </table>
  </div>
`;

let selectedContactId = null;
let selectedContactFirstName = null;
let selectedContactLastName = null;

// Function to display the initial search results modal
function showSearchResultsModal() {
  Swal.fire({
    icon: "info",
    title: `Select Contact`,
    html: recordHtml,
    width: "70rem",
    showCancelButton: true,
    showConfirmButton: includeAddContactButton,
    cancelButtonText: "Close Search",
    confirmButtonText: 'Add New Contact'
  }).then(result => {
    if(result.isConfirmed) {
      addNewContactRecord();
    } else if(result.isDismissed) {
      clearFieldsCallback();
    }
  });

  // Style adjustments for the modal content
  $(".records-container").css({
    "max-height": "320px",
    "overflow-y": "auto",
    "overflow-x": "auto",
  });

  $(".record-table").css({
    width: "100%",
    "border-collapse": "collapse",
  });

  $(".record-table th, .record-table td").css({
    padding: "8px",
    "border": "1px solid #333",
    "text-align": "center",
  });

  $(".record-row:nth-child(odd)").css({
    "background-color": "#f9f9f9",
  });

  $(".record-row:nth-child(even)").css({
    "background-color": "white",
  });

  // Rebind the click event to each "Add Contact" button
  $(".add-btn").off("click").on("click", function () {
    selectedContactId = $(this).data("formid");
    selectedContactFirstName = $(this).data("firstname");
    selectedContactLastName = $(this).data("lastname");

    if (selectedContactId && selectedContactFirstName && selectedContactLastName) {
      if(role === "Landowner") {
        if(isBusinessSigner) {
          showAssociateBusinessModal();
        }else{
          showSameAsModal();
        }
      } else {
        if(isBusinessSigner) {
          showAssociateBusinessModal();
        }else{
          showAddContactModal('No', 'No'); // Pass 'No' for both same as questions
        }        
      }
    }
  });
}

// Generate dropdown options for the 'Same As' modal
const dropdownOptions = `
  <option value="">Select</option>
  <option value="Yes">Yes</option>
  <option value="No">No</option>
`;

// Function to display the "Same As" modal
function showSameAsModal(selectedBusinessId, selectedBusinessName) {
  // Retrieve saved selections from session storage
  const savedRole1SameAs = sessionStorage.getItem('role1SameAs') || '';
  const savedRole2SameAs = sessionStorage.getItem('role2SameAs') || '';

  const sameAsHtml = `
  <p style="text-align: left; line-height: 1.6;">Please answer the following questions before adding the contact:</p>
  <div style="display: flex; flex-direction: column; gap: 1rem; padding: 1rem 0;">
    <div style="display: flex; align-items: center; gap: 1rem; width: 100%;">
      <label for="role1SameAs" style="flex: 1 0 50%; text-align: left; white-space: nowrap;">
        Is the ${role1} the same as the ${mainRole}?
      </label>
      <select id="role1SameAs" style="flex: 1 0 25%; padding: 0.3rem;">${dropdownOptions}</select>
    </div>
    <div style="display: flex; align-items: center; gap: 1rem; width: 100%;">
      <label for="role2SameAs" style="flex: 1 0 50%; text-align: left; white-space: nowrap;">
        Is the ${role2} the same as the ${mainRole}?
      </label>
      <select id="role2SameAs" style="flex: 1 0 25%; padding: 0.3rem;">${dropdownOptions}</select>
    </div>
  </div>
`;

  Swal.fire({
    icon: 'question',
    title: `Same as ${mainRole}?`,
    html: sameAsHtml,
    showCancelButton: true,
    showConfirmButton: true,
    showDenyButton: true,
    allowOutsideClick: false,
    confirmButtonText: 'Back',
    denyButtonText: 'Next',
    cancelButtonText: 'Cancel',
    width: '50rem', // Modal width
    customClass: {
      confirmButton: 'blue-button back-button',
      denyButton: 'blue-button next-button',
      cancelButton: 'blue-button cancel-button',
    },
    preDeny: () => {
      const role1Value = document.getElementById('role1SameAs').value;
      const role2Value = document.getElementById('role2SameAs').value;

      if (!role1Value || !role2Value) {
        Swal.showValidationMessage(`The 'Same As ${mainRole}' questions must be answered.`);
        return false;
      }

      // Save selections to session storage
      sessionStorage.setItem('role1SameAs', role1Value);
      sessionStorage.setItem('role2SameAs', role2Value);

      return { role1SameAs: role1Value, role2SameAs: role2Value };
    },
    didRender: () => {
      // Rearrange buttons
      const actions = Swal.getActions(); // Get the actions container
      const confirmButton = Swal.getConfirmButton(); // Back button
      const denyButton = Swal.getDenyButton(); // Next button
      const cancelButton = Swal.getCancelButton(); // Cancel button

      // Set custom order using flexbox order property
      confirmButton.style.order = 1; // Back button
      denyButton.style.order = 2; // Next button
      cancelButton.style.order = 3; // Cancel button

      // Ensure the actions container uses flexbox
      actions.style.display = 'flex';

      // Directly modify the deny button style after rendering
      $('.swal2-deny').css({
        'background-color': $('.swal2-confirm').css('background-color'),
        color: $('.swal2-confirm').css('color'),
      });

      // Set the dropdowns to saved values if available
      document.getElementById('role1SameAs').value = savedRole1SameAs;
      document.getElementById('role2SameAs').value = savedRole2SameAs;
    },
  }).then((result) => {
    if (result.isConfirmed) {
      if(isBusinessSigner) {
        showAssociateBusinessModal();
      }else{
        showSearchResultsModal(); // Go back to the "Select Contact" modal
      }      
    } else if (result.isDenied) {
      const { role1SameAs, role2SameAs } = result.value;
      // Proceed to Add Contact modal, pass the record and same as values
      showAddContactModal(role1SameAs, role2SameAs, selectedBusinessId, selectedBusinessName); // Call the "Add Contact" modal
    } else if (result.isDismissed) {
      // Clear selections if modal is dismissed via Cancel button
      sessionStorage.removeItem('role1SameAs');
      sessionStorage.removeItem('role2SameAs');

      // Call clearFieldsCallback when modal is closed or canceled
      clearFieldsCallback();
    }
  });
}

// Function to display the "Add Contact" modal
function showAddContactModal(role1SameAs, role2SameAs, selectedBusinessId, selectedBusinessName) {
  let addContactHtml;

  if(!isBusinessSigner){
    addContactHtml = `
    <div style="text-align: left; line-height: 1.6;">
      <p>Are you sure you want to associate the selected contact as a ${mainRole}?</p>
      <p><strong>Name:</strong> ${selectedContactFirstName} ${selectedContactLastName}</p>
      <p style='display: ${role === 'Landowner' ? 'absolut' : 'none'}'><strong>${mainRole} same as ${role1}:</strong> ${role1SameAs}</p>
      <p style='display: ${role === 'Landowner' ? 'absolut' : 'none'}'><strong>${mainRole} same as ${role2}:</strong> ${role2SameAs}</p>
    </div>
  `;
  }else{    
    addContactHtml = `
    <div style="text-align: left; line-height: 1.6;">
      <p>Are you sure you want to associate the selected contact as a Business Signer?</p>
      <p><strong>Business Signer:</strong> ${selectedContactFirstName} ${selectedContactLastName}</p>
      <p><strong>${mainRole}:</strong> ${selectedBusinessName}</p>
      <p style='display: ${role === 'Landowner' ? 'absolut' : 'none'}'><strong>${mainRole} same as ${role1}:</strong> ${role1SameAs}</p>
      <p style='display: ${role === 'Landowner' ? 'absolut' : 'none'}'><strong>${mainRole} same as ${role2}:</strong> ${role2SameAs}</p>
    </div>
  `;
  }

  Swal.fire({
    icon: 'question',
    title: `Add ${isBusinessSigner ? 'Business Signer' : mainRole}`,
    html: addContactHtml,
    showCancelButton: true,
    showConfirmButton: true,
    showDenyButton: true,
    allowOutsideClick: false,
    confirmButtonText: 'Back',
    denyButtonText: `Add ${isBusinessSigner ? 'Business Signer' : mainRole}`,
    cancelButtonText: 'Cancel',
    width: '40rem', // Modal width for Add Contact
    didRender: () => {
      // Rearrange buttons
      const actions = Swal.getActions(); // Get the actions container
      const confirmButton = Swal.getConfirmButton(); // Back button
      const denyButton = Swal.getDenyButton(); // Add Contact button
      const cancelButton = Swal.getCancelButton(); // Cancel button

      // Set custom order using flexbox order property
      confirmButton.style.order = 1; // Back button
      denyButton.style.order = 2; // Add Contact button
      cancelButton.style.order = 3; // Cancel button

      // Directly modify the deny button style after rendering
      $('.swal2-deny').css({
        'background-color': $('.swal2-confirm').css('background-color'),
        color: $('.swal2-confirm').css('color'),
      });

      // Ensure the actions container uses flexbox
      actions.style.display = 'flex';
    },
  }).then((result) => {
    if (result.isConfirmed) {
      if(role === "Landowner"){
        showSameAsModal(selectedBusinessId, selectedBusinessName); // Go back to the "Same As" modal
      } else {
        if(isBusinessSigner) {
          showAssociateBusinessModal(); // Go to "Associate Business" modal
        } else {
          showSearchResultsModal(); // Go back to the "Select Contact" modal
        }
      }
    } else if (result.isDenied) {
      // Clear selections when contact is added
      sessionStorage.removeItem('role1SameAs');
      sessionStorage.removeItem('role2SameAs');

      VV.Form.DoAjaxFormSave().then(() => {
        addSelectedContact(
          selectedContactId,
          role1SameAs,
          role2SameAs,
          selectedBusinessId
        );
      });
    } else if (result.isDismissed) {
      // Clear selections if modal is dismissed via Cancel button
      sessionStorage.removeItem('role1SameAs');
      sessionStorage.removeItem('role2SameAs');

      // Call clearFieldsCallback when modal is closed or canceled
      clearFieldsCallback();
    }
  });
}

// Callback function to add the selected contact record and other params
function addSelectedContact(contactId, role1SameAs, role2SameAs, selectedBusinessId) {
    // Construct the roles array based on the boolean parameters
    let roles = [mainRole];
    if (role1SameAs === 'Yes') {
        roles.push(role1);
    }
    if (role2SameAs === 'Yes') {
        roles.push(role2);
    }

    if(isBusinessSigner){    
      roles.push('Business Signer');
    }

    VV.Form.Template.AddContact(contactId, selectedContactFirstName, selectedContactLastName, roles, selectedBusinessId, isBusinessSigner);
    clearFieldsCallback();
}

function addNewContactRecord() {
  const contactData = {
    contactFirstName: VV.Form.GetFieldValue(`${prefix} First Name`),
    contactLastName: VV.Form.GetFieldValue(`${prefix} Last Name`),
    contactCountry: VV.Form.GetFieldValue(`${prefix} Country`),
    contactZipCode: VV.Form.GetFieldValue(`${prefix} Postal Zip Code`),
    contactAddressLine1: VV.Form.GetFieldValue(`${prefix} Address Line 1`),
    contactAddressLine2: VV.Form.GetFieldValue(`${prefix} Address Line 2`),
    contactAddressLine3: VV.Form.GetFieldValue(`${prefix} Address Line 3`),
    contactCity: VV.Form.GetFieldValue(`${prefix} City`),
    contactProvinceState: VV.Form.GetFieldValue(`${prefix} Province State`),
    contactCounty: VV.Form.GetFieldValue(`${prefix} County`),
    contactPhone: VV.Form.GetFieldValue(`${prefix} Phone`),
    contactEmail: VV.Form.GetFieldValue(`${prefix} Email`),
    role: role,
    relationType: isBusinessSigner ? "Business" : "Individual"
  };

  VV.Form.Template.AddNewContact(contactData);
}

// Function to display the "Associate Business" modal
function showAssociateBusinessModal(selectedBusinessId, selectedBusinessName) {
  //Use query to get all Business records already associated
  VV.Form.Global.UseCustomQuery(
    role === 'Landowner' 
      ? 'zClientSideGetAssociatedLandownerBusiness'
      : role === 'Timber Owner'
        ? 'zClientSideGetAssociatedTimberOwnerBusiness'
        : 'zClientSideGetAssociatedOperatorBusiness',
    VV.Form.DhDocID,
    `[Business Name] <> '${Math.random()}'`
  ).then((response) => {

    const recordHtmlArray = response.map(record => `
      <tr class="record-row">
        <td>${record["business Name"] || 'N/A'}</td>
        <td>${record["business ID Number"] || 'N/A'}</td>
        <td>${record["business Address Line 1"] || 'N/A'}</td>
        <td>${record["business City"] || 'N/A'}</td>
        <td>${record["business Province State"] || 'N/A'}</td>
        <td>${record["business Zip Code"] || 'N/A'}</td>
        <td>${record["business Country"] || 'N/A'}</td>
        <td><button class="k-button ng-star-inserted add-btn" data-formid="${record["business ID"]}" data-businessname="${record["business Name"]}">Select Business</button></td>
      </tr>
    `).join("");

    console.log(recordHtmlArray);

    // Complete HTML structure for the modal, including table headers and rows
    const associateHtml = `
    <p style="text-align: left; line-height: 1.6;">You are adding this contact as a Business Signer. To continue, please select a business from the list below and click
    'Select Business' to associate it with the contact.</p>
    <div class="records-container">
      <table class="record-table">
        <thead>
          <tr>
            <th>Business Name</th>
            <th>ID Number</th>
            <th>Address</th>
            <th>City</th>
            <th>State/Province</th>
            <th>Postal/Zip Code</th>
            <th>Country</th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          ${recordHtmlArray}
        </tbody>
      </table>
    </div>
  `;

    Swal.fire({
      icon: "info",
      title: `Business Signer Search`,
      html: associateHtml,
      showCancelButton: true,
      showConfirmButton: true,
      showDenyButton: false,
      allowOutsideClick: false,
      confirmButtonText: "Back",
      //denyButtonText: "Next",
      cancelButtonText: "Close Search",
      width: "70rem", // Modal width
      customClass: {
        confirmButton: "blue-button back-button",
        //denyButton: "blue-button next-button",
        cancelButton: "blue-button cancel-button",
      },
      didRender: () => {
        // Rearrange buttons
        const actions = Swal.getActions(); // Get the actions container
        const confirmButton = Swal.getConfirmButton(); // Back button
        const cancelButton = Swal.getCancelButton(); // Close Search button

        // Set custom order using flexbox order property
        confirmButton.style.order = 1; // Back button
        cancelButton.style.order = 2;  // Cancel button

        // Ensure the actions container uses flexbox
        actions.style.display = 'flex';

        // Directly modify the deny button style after rendering
        $(".swal2-deny").css({
          "background-color": $(".swal2-confirm").css("background-color"),
          "color": $(".swal2-confirm").css("color"),
        });
      },
    }).then((result) => {
      if (result.isConfirmed) {
        showSearchResultsModal(); // Go back to the "Select Contact" modal
      } else if (result.isDismissed) {
        // Close modal
        // Call clearFieldsCallback when modal is closed or canceled
        clearFieldsCallback();
      }
    });

    // Style adjustments for the modal content
    $(".records-container").css({
      "max-height": "320px",
      "overflow-y": "auto",
      "overflow-x": "hidden",
    });

    $(".record-table").css({
      width: "100%",
      "border-collapse": "collapse",
    });

    $(".record-table th, .record-table td").css({
      padding: "8px",
      "border": "1px solid #333",
      "text-align": "center",
    });

    $(".record-row:nth-child(odd)").css({
      "background-color": "#f9f9f9",
    });

    $(".record-row:nth-child(even)").css({
      "background-color": "white",
    });

    // Rebind the click event to each "Add Business" button
    $(".add-btn").off("click").on("click", function () {
      const selectedBusinessId = $(this).data("formid");
      const selectedBusinessName = $(this).data("businessname");

      if(role === "Landowner") {
        showSameAsModal(selectedBusinessId, selectedBusinessName); // Go to "Same As" modal 
      } else{
        showAddContactModal('No', 'No', selectedBusinessId, selectedBusinessName); // Pass 'No' for both same as questions
      }
    });

  });
}

// Initial call to display the search results modal
showSearchResultsModal();

VV.Form.Global.DisplayModalRemoveHiddenSweetAlertElements();

// Business or Individual
const businessOrindividual = VV.Form.GetFieldValue(
  "Timber Owner Business Or Individual"
);
let term;
let addButtonName;
let helpText;

// Determine the signer type
if (businessOrindividual === 'Business') {
  term = 'Business Signer';
  addButtonName = 'Add Business';
  helpText = `Please select one of the business records below and click 'Add Business' to associate a business with this application. Note: To make changes to your Business record (e.g., mailing address) please contact your local region office. This can be done before or after you have submitted your application`
} else if (businessOrindividual === 'Individual') {
  term = 'Timber Owner';
  addButtonName = 'Add Contact'
  helpText = `Please select one of the contact records below and click 'Add Contact' to associate a contact with this application. Note: To make changes to your contact record (e.g., mailing address) please contact your local region office. This can be done before or after you have submitted your application.`
} else {
  // Display error message and stop execution
  VV.Form.Global.DisplayModal({
    Icon: 'error',
    Title: 'Selection Required',
    HtmlContent: 'Please select a Business or Individual from the Business Individual dropdown.',
  });
  return; // Stop further execution
}

// Function to display the "Select Contact" modal
function showSelectContactModal() {
  const recordHtmlArray = recordsArray
    .map(
      (record) => `
        <tr class="record-row">
          <td>${record["first Name"] || "N/A"}</td>
          <td>${record["last Name"] || "N/A"}</td>
          <td>${record["address Line 1"] || "N/A"}</td>
          <td>${record["city"] || "N/A"}</td>
          <td>${record["state"] || "N/A"}</td>
          <td>${record["zip Code"] || "N/A"}</td>
          <td>${record["phone"] || "N/A"}</td>
          <td>
            <button class="k-button add-btn" data-formid="${
              record["contact Information ID"]
            }">
              ${addButtonName}
            </button>
          </td>
        </tr>
      `
    )
    .join("");

  const recordHtml = `
    <p>
      ${helpText}
    </p>
    <div class="records-container">
      <table class="record-table">
        <thead>
          <tr>
            <th>First Name</th>
            <th>Last Name</th>
            <th>Address</th>
            <th>City</th>
            <th>State/Province</th>
            <th>Postal/Zip Code</th>
            <th>Phone</th>
            <th></th>
          </tr>
        </thead>
        <tbody>${recordHtmlArray}</tbody>
      </table>
    </div>
  `;

  Swal.fire({
    icon: "info",
    title: `${term} Search`,
    html: recordHtml,
    width: "70rem", // Adjust modal width
    showConfirmButton: false,
    showCancelButton: true,
    cancelButtonText: "Close Search",
    allowOutsideClick: false,
    didRender: () => {
      // Apply styles after rendering
      $(".records-container").css({
        "max-height": "320px",
        "overflow-y": "auto",
        "overflow-x": "hidden",
      });

      $(".record-table").css({
        width: "100%",
        "border-collapse": "collapse",
      });

      $(".record-table th, .record-table td").css({
        padding: "8px",
        border: "1px solid #333",
        "text-align": "center",
      });

      $(".record-row:nth-child(odd)").css({
        "background-color": "#f9f9f9",
      });

      $(".record-row:nth-child(even)").css({
        "background-color": "white",
      });

      // Add click event to buttons
      $(".add-btn")
        .off("click")
