/*
    Function Name: Form_onLoad - FPAN Renewal
    Customer:      Washington DNR
    Purpose:       This function initializes the FPAN Renewal form.
                   It registers all DataGrids, ensures that the form instance is persisted
                   on first load, updates the browser URL to reference the saved record,
                   and sets up user roles, FPAN relations, and document paths.

    Parameters:    None

    Date of Dev:   --/--/----
    Last Rev Date: 11/26/2025

    --/--/---- - Previous contributors: Initial revision
    10/31/2025 - Matias Andrade: Added early form persistence and browser URL update logic
                                 to ensure the saved record reloads correctly after refresh.
    11/26/2025 - Federico Cuelho: Update save logic to condition initial save when there are unsaved changes and final save after changes were made.
    01/07/2026 - Santiago Tortu: Add showLoadingPanel field to the form and set it to true before loading starts and false when loading completes successfully or with error.
    01/18/2026 - Zharich Barona: Send parameters to EnterValidFPANNumber function to specify the template name for context in the FPAN validation flow.
*/

// Set status if not set previously
if (VV.Form.Global.isNullEmptyUndefined(VV.Form.GetFieldValue('Status'))) {
  VV.Form.SetFieldValue('Status', 'Draft');
}

// Get roles directly (synchronous)
const currentRolesGlobal = VV.Form.Global.GetCurrentRoles();

const isSignatory = currentRolesGlobal.some((role) => role === 'signatory');

if (isSignatory) {
  VV.Form.Global.SignatoryDisableButtonByFieldName('btn_UploadDocumentation');
}

// Register DataGrids
try {
  VV.Form.Global.RegisterDatagrids([
    'DG Landowner Businesses',
    'DG Landowners',
    'DG Landowner Business Signers',
    'DG Timber Owner Businesses',
    'DG Timber Owners',
    'DG Timber Owner Business Signers',
    'DG Operator Businesses',
    'DG Operators',
    'DG Operator Business Signers',
  ]);
} catch (error) {
  console.error('Error registering datagrids:', error);
}

// Initialize variables
const fpanNumber = VV.Form.GetFieldValue('FPAN Number');
const needsRelationLoading = VV.Form.GetFieldValue('Relations Loaded In') == 'False' && fpanNumber;
const isSaved = VV.Form.GetFieldValue('Form Saved') === 'True';

// Handle "No Fees Required" field for pending revisions
try {
  const formStatus = VV.Form.GetFieldValue('Status');
  if (formStatus.toLowerCase() === 'pending revisions') {
    VV.Form.SetFieldValue('No Fees Required', 'False');
  }
} catch (error) {
  console.error('Error setting No Fees Required field:', error);
}

VV.Form.ShowLoadingPanel();

// Early Save + URL Update
(VV.Form.UnsavedChanges > 0 ? VV.Form.DoAjaxFormSave() : Promise.resolve())
  .then(() => {
    try {
      VV.Form.Global.UpdateWindowLocationURL();
    } catch (urlErr) {
      console.error('Error updating URL after first save:', urlErr);
    }

    // Main execution chain - handle roles and sequential operations
    let rolesCache = [];

    return Promise.all([VV.Form.Global.GetCurrentRoles(), VV.Form.GetFieldValue('UserRoles')])
      .then(([roles, currentRoles]) => {
        rolesCache = roles;

        // Determine updated roles
        const updatedRoles = VV.Form.Global.isNullEmptyUndefined(currentRoles)
          ? roles.join('|')
          : currentRoles;

        return updatedRoles;
      })
      .then((updatedRoles) => {
        VV.Form.SetFieldValue('UserRoles', updatedRoles);

        const isOfficeStaff = rolesCache.some(
          (role) =>
            role.toString().toLowerCase() === 'office staff' ||
            role.toString().toLowerCase() === 'vaultaccess'
        );
        const isProponent = rolesCache.some(
          (role) => role.toString().toLowerCase() === 'proponent'
        );

        const setFieldPromises = [];

        if (isOfficeStaff) {
          setFieldPromises.push(VV.Form.SetFieldValue('isOfficeStaff', 'True', true));

          if (!isSaved) {
            setFieldPromises.push(VV.Form.SetFieldValue('Created By Office Staff', 'True', true));
          }
        } else {
          setFieldPromises.push(VV.Form.SetFieldValue('isOfficeStaff', 'False', true));
        }

        if (isProponent) {
          setFieldPromises.push(VV.Form.SetFieldValue('isProponent', 'True', true));
        } else {
          setFieldPromises.push(VV.Form.SetFieldValue('isProponent', 'False', true));
        }

        return Promise.all(setFieldPromises).then(() => {
          const IndividualIdPresent = VV.Form.GetFieldValue('Individual ID') !== '';
          const UserIdPresent = VV.Form.GetFieldValue('UserID') !== '';

          const needsSetIndividual = isProponent && !IndividualIdPresent && !UserIdPresent;

          return needsSetIndividual;
        });
      })
      .then((needsSetIndividual) => {
        // Execute SetIndividual if needed and wait for completion
        if (needsSetIndividual) {
          return VV.Form.Template.SetIndividual();
        }
        return Promise.resolve();
      })
      .then(() => {
        // Load FPAN relations if needed
        // Note: LoadInFPANRelations saves the form internally on success
        if (needsRelationLoading) {
          return VV.Form.Global.LoadInFPANRelations();
        } else if (!fpanNumber) {
          // If FPAN Number is missing, prompt user to enter it
          return VV.Form.Global.EnterValidFPANNumber(null,null,'FPAN Renewal');
        }
        return Promise.resolve();
      })
      .then(() => {
        // Update document path after all business logic completes
        return VV.Form.Template.UpdateDocumentPath();
      })
      .then(() => {
        // Set button visibility after document path is updated
        return VV.Form.Template.SetButtonVisibility();
      })
      .then(() => {
        // Determine Pay Now button visibility as final step
        return VV.Form.Template.DeterminePayNowButtonVisibility();
      })
      .then(() => {
        // Save form at the end if relations weren't loaded (since LoadInFPANRelations saves internally)
        if (!needsRelationLoading && VV.Form.UnsavedChanges > 0) {
          return VV.Form.DoAjaxFormSave();
        }
        return Promise.resolve();
      })
      .then(() => {
        // Final save if there are any remaining unsaved changes
        if (VV.Form.UnsavedChanges > 0) {
          return VV.Form.DoAjaxFormSave();
        }
        return Promise.resolve();
      })
      .then(() => {
        // Set showLoadingPanel field to false when loading completes successfully
        VV.Form.SetFieldValue('showLoadingPanel', 'False');
        VV.Form.HideLoadingPanel();
      })
      .catch((error) => {
        console.error('Error in sequential execution:', error);

        try {
          VV.Form.Template.UpdateDocumentPath();
        } catch (docError) {
          console.error('Error setting document upload path in catch:', docError);
        }

        try {
          VV.Form.Template.SetButtonVisibility();
        } catch (buttonError) {
          console.error('Error setting button visibility in catch:', buttonError);
        }

        try {
          VV.Form.Template.DeterminePayNowButtonVisibility();
        } catch (payError) {
          console.error('Error determining pay now button visibility in catch:', payError);
        }
        // Set showLoadingPanel field to false when loading completes with error
        VV.Form.SetFieldValue('showLoadingPanel', 'False');
        VV.Form.HideLoadingPanel();
      });
  })
  .catch((error) => {
    console.error('Error during initial save / URL update:', error);

    // Set showLoadingPanel field to false when loading completes with error
    VV.Form.SetFieldValue('showLoadingPanel', 'False');
    VV.Form.HideLoadingPanel();
  });

