/*
    Function Name: btnRemoveSelectedLandownerBusinessSigner_onClick - Renewal Request
    Customer:      Washington DNR
    Purpose:       Click handler for the "Remove Selected" button in the "DG Landowners" DataGrid.
                   Determines whether the Landowner is Business or Individual and calls the shared removal library
                   to remove the selected Contact Information relationship from the parent record.

    Parameters:    None

    Date of Dev:   --/--/----
    Last Rev Date: 12/26/2025

    --/--/---- - Previous contributors: Initial revision
    12/26/2025 - Matias Andrade: Updated the type parameter passed to the removal library ("Business Signer" vs "Individual") to match the underlying Contact Information record type.
*/

const MAX_QUANTITY = 10;
const selectedItems = VV.Form.Template.DatagridFindSelectedRowsCIRID("DG Landowner Business Signers");
const isBusiness = VV.Form.GetFieldValue("Landowner Business Or Individual") === "Business";
const type = isBusiness ? "Business Signer" : "Individual"

const doOkFunction = () =>
  VV.Form.Template.RemoveSelectedContactInformationRelation(selectedItems, "Landowner", type)

if (selectedItems.length > 0 && selectedItems.length <= MAX_QUANTITY) {
  const htmlContent = `<p>Do you want to remove the selected ${type}</p>`;

  VV.Form.Global.DisplayModal({
    HtmlContent: htmlContent,
    Icon: "question",
    okFunction: doOkFunction,
    Title: "Confirmation",
  });
} else {
  const htmlContent = `<p>Please select at least one ${type} to remove.</p>`;

  VV.Form.Global.DisplayModal({
    HtmlContent: htmlContent,
    Icon: "error",
    Title: "Error",
  });
}

